#include <vector>
#include <string>
#include <algorithm>
#include <regex>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<string> validCoupons;
    vector<pair<int, string>> electronics, grocery, pharmacy, restaurant;

    for (int i = 0; i < code.size(); ++i) {
        // Check if the coupon is active
        if (!isActive[i]) continue;

        // Check if the business line is valid
        if (businessLine[i] != "electronics" && businessLine[i] != "grocery" && 
            businessLine[i] != "pharmacy" && businessLine[i] != "restaurant") {
            continue;
        }

        // Check if the code is valid (non-empty and only alphanumeric + underscore)
        if (code[i].empty()) continue;
        bool isValidCode = true;
        for (char c : code[i]) {
            if (!isalnum(c) && c != '_') {
                isValidCode = false;
                break;
            }
        }
        if (!isValidCode) continue;

        // If all conditions are met, add to the corresponding business line vector
        if (businessLine[i] == "electronics") {
            electronics.emplace_back(i, code[i]);
        } else if (businessLine[i] == "grocery") {
            grocery.emplace_back(i, code[i]);
        } else if (businessLine[i] == "pharmacy") {
            pharmacy.emplace_back(i, code[i]);
        } else if (businessLine[i] == "restaurant") {
            restaurant.emplace_back(i, code[i]);
        }
    }

    // Sort each business line's coupons by code (lex order)
    auto sortByCode = [](const pair<int, string>& a, const pair<int, string>& b) {
        return a.second < b.second;
    };

    sort(electronics.begin(), electronics.end(), sortByCode);
    sort(grocery.begin(), grocery.end(), sortByCode);
    sort(pharmacy.begin(), pharmacy.end(), sortByCode);
    sort(restaurant.begin(), restaurant.end(), sortByCode);

    // Concatenate all valid coupons in the required order
    for (const auto& p : electronics) {
        validCoupons.push_back(p.second);
    }
    for (const auto& p : grocery) {
        validCoupons.push_back(p.second);
    }
    for (const auto& p : pharmacy) {
        validCoupons.push_back(p.second);
    }
    for (const auto& p : restaurant) {
        validCoupons.push_back(p.second);
    }

    return validCoupons;
}

